/**
 * Endpoint to search for Mapillary street level images near a given lat/lng
 */
app.get("/api/mapillary/search", async (req, res) => {
  const { lat, lng } = req.query;

  if (!lat || !lng) {
    return res.status(400).json({ error: "Parâmetros 'lat' e 'lng' são obrigatórios." });
  }

  const latitude = parseFloat(lat as string);
  const longitude = parseFloat(lng as string);

  // We will perform an expanding bounding box search up to 6 times to find nearby street-level images.
  // Using smaller, more granular offsets to avoid overloading the Mapillary API with too many points
  // in high-density locations, which can trigger a Status 500 "Please reduce the amount of data" error.
  const searchRadii = [0.0005, 0.0015, 0.003, 0.006, 0.012, 0.018]; // ~50m, ~150m, ~300m, ~600m, ~1.3km, ~2km offset

  for (let i = 0; i < searchRadii.length; i++) {
    const offset = searchRadii[i];
    const min_lon = longitude - offset;
    const max_lon = longitude + offset;
    const min_lat = latitude - offset;
    const max_lat = latitude + offset;

    const bbox = `${min_lon},${min_lat},${max_lon},${max_lat}`;
    const url = `https://graph.mapillary.com/images?access_token=${MAPILLARY_TOKEN}&fields=id,geometry,captured_at,compass_angle&bbox=${bbox}&limit=15`;

    try {
      console.log(`[Mapillary] Pesquisando raio ${offset} para coordenadas [${latitude}, ${longitude}]`);
      const response = await fetch(url);
      
      if (!response.ok) {
        const errorText = await response.text();
        console.error(`[Mapillary API Error] Status ${response.status}: ${errorText}`);
        
        // If we hit a density/limit error, do not throw. Just log it and continue to other radii or fallback.
        if (response.status === 500 || errorText.includes("reduce the amount of data")) {
          console.warn(`[Mapillary] Densidade de dados muito alta no raio ${offset}. Pulando este raio.`);
          continue;
        }
        throw new Error(`Erro na API do Mapillary: ${response.statusText}`);
      }

      const data = (await response.json()) as { data: Array<{ id: string; geometry: { coordinates: [number, number] }; captured_at: number; compass_angle?: number }> };

      if (data && data.data && data.data.length > 0) {
        // Find the image closest to our query lat, lng using basic Euclidean distance approximation
        let closestImage = data.data[0];
        let minDistance = Infinity;

        for (const img of data.data) {
          const imgLng = img.geometry.coordinates[0];
          const imgLat = img.geometry.coordinates[1];
          const dist = Math.pow(imgLat - latitude, 2) + Math.pow(imgLng - longitude, 2);
          if (dist < minDistance) {
            minDistance = dist;
            closestImage = img;
          }
        }

        console.log(`[Mapillary] Ponto encontrado no raio ${offset}. Imagem ID: ${closestImage.id}`);
        return res.json({
          imageId: closestImage.id,
          coordinates: {
            lat: closestImage.geometry.coordinates[1],
            lng: closestImage.geometry.coordinates[0],
          },
          capturedAt: closestImage.captured_at,
          compassAngle: closestImage.compass_angle || 0,
        });
      }
    } catch (error: any) {
      console.error("[Mapillary Search Error] Falha ao consultar o Mapillary no raio:", offset, error.message);
      // If it's a critical error (like token invalid), don't keep trying
      if (error.message && error.message.includes("403")) {
        break;
      }
    }
  }

  // If no point was found, return a fallback default point (e.g. Copacabana Rio de Janeiro)
  // this ensures the game never gets stuck!
  console.log("[Mapillary] Nenhum ponto encontrado nas proximidades. Usando fallback de segurança.");
  return res.json({
    imageId: "142364711204983", // Copacabana Rio fallback
    coordinates: { lat: -22.9711, lng: -43.1822 },
    capturedAt: 1618394800,
    compassAngle: 90,
    isFallback: true
  });
});

/**
 * Helper to redact sensitive names from the Wikipedia summaries
 */
function redactText(text: string, wordsToRedact: string[]): string {
  if (!text) return "";
  
  const sensitiveWords = new Set<string>();
  
  for (const word of wordsToRedact) {
    if (!word) continue;
    const trimmed = word.trim();
    if (trimmed.length > 2) {
      sensitiveWords.add(trimmed.toLowerCase());
      // Add common plural/gender variations
      if (trimmed.endsWith("o") || trimmed.endsWith("O")) {
        sensitiveWords.add(trimmed.slice(0, -1).toLowerCase() + "a");
        sensitiveWords.add(trimmed.toLowerCase() + "s");
        sensitiveWords.add(trimmed.slice(0, -1).toLowerCase() + "as");
      } else if (trimmed.endsWith("a") || trimmed.endsWith("A")) {
        sensitiveWords.add(trimmed.slice(0, -1).toLowerCase() + "o");
        sensitiveWords.add(trimmed.toLowerCase() + "s");
        sensitiveWords.add(trimmed.slice(0, -1).toLowerCase() + "os");
      }
    }
  }

  const escapeRegExp = (string: string) => {
    return string.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  };

  let redactedText = text;

  if (sensitiveWords.size > 0) {
    // Sort by descending length so longer compounds are redacted first
    const sortedWords = Array.from(sensitiveWords).sort((a, b) => b.length - a.length);
    for (const word of sortedWords) {
      try {
        const escaped = escapeRegExp(word);
        // Build accent-insensitive regex match for each vowel
        const pattern = escaped
          .replace(/[aáàâãä]/gi, "[aáàâãä]")
          .replace(/[eéèêë]/gi, "[eéèêë]")
          .replace(/[iíìîï]/gi, "[iíìîï]")
          .replace(/[oóòôõö]/gi, "[oóòôõö]")
          .replace(/[uúùûü]/gi, "[uúùûü]")
          .replace(/[cç]/gi, "[cç]");
        
        const regex = new RegExp(`\\b${pattern}\\w*\\b`, "gi");
        redactedText = redactedText.replace(regex, "█████");
      } catch (e) {
        const regex = new RegExp(`\\b${escapeRegExp(word)}\\w*\\b`, "gi");
        redactedText = redactedText.replace(regex, "█████");
      }
    }
  }

  return redactedText;
}

/**
 * Fetch Nominatim Address Details
 */
async function fetchAddressDetails(lat: number, lng: number) {
  try {
    const url = `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&accept-language=pt,en`;
    const res = await fetch(url, {
      headers: {
        "User-Agent": "GuessThePlaceApplet/2.0 (marinasheylla@gmail.com)"
      }
    });
    if (res.ok) {
      const data = (await res.json()) as any;
      return data.address;
    }
  } catch (err) {
    console.error("[Nominatim Error] Falha ao geocodificar reversamente:", err);
  }
  return null;
}

/**
 * Fetch RestCountries details
 */
async function fetchCountryDetails(countryCode: string) {
  try {
    const url = `https://restcountries.com/v3.1/alpha/${countryCode}`;
    const res = await fetch(url);
    if (res.ok) {
      const data = (await res.json()) as any;
      if (Array.isArray(data) && data.length > 0) {
        return data[0];
      }
    }
  } catch (err) {
    console.error("[RestCountries Error] Falha ao buscar detalhes do país:", err);
  }
  return null;
}

/**
 * Search Wikipedia and return extract text
 */
async function fetchWikipediaExtract(searchQuery: string): Promise<string | null> {
  try {
    // 1. Search in Portuguese Wikipedia first
    const searchUrl = `https://pt.wikipedia.org/w/api.php?action=query&list=search&srsearch=${encodeURIComponent(searchQuery)}&utf8=1&format=json&origin=*`;
    const searchRes = await fetch(searchUrl);
    if (searchRes.ok) {
      const searchData = (await searchRes.json()) as any;
      const results = searchData.query?.search;
      if (results && results.length > 0) {
        const bestTitle = results[0].title;
        const extractUrl = `https://pt.wikipedia.org/w/api.php?action=query&prop=extracts&exintro=1&explaintext=1&titles=${encodeURIComponent(bestTitle)}&format=json&origin=*`;
        const extractRes = await fetch(extractUrl);
        if (extractRes.ok) {
          const extractData = (await extractRes.json()) as any;
          const pages = extractData.query?.pages;
          if (pages) {
            const pageId = Object.keys(pages)[0];
            if (pageId && pages[pageId] && pages[pageId].extract) {
              return pages[pageId].extract;
            }
          }
        }
      }
    }

    // Fallback: search English Wikipedia
    const searchUrlEn = `https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch=${encodeURIComponent(searchQuery)}&utf8=1&format=json&origin=*`;
    const searchResEn = await fetch(searchUrlEn);
    if (searchResEn.ok) {
      const searchDataEn = (await searchResEn.json()) as any;
      const resultsEn = searchDataEn.query?.search;
      if (resultsEn && resultsEn.length > 0) {
        const bestTitleEn = resultsEn[0].title;
        const extractUrlEn = `https://en.wikipedia.org/w/api.php?action=query&prop=extracts&exintro=1&explaintext=1&titles=${encodeURIComponent(bestTitleEn)}&format=json&origin=*`;
        const extractResEn = await fetch(extractUrlEn);
        if (extractResEn.ok) {
          const extractDataEn = (await extractResEn.json()) as any;
          const pagesEn = extractDataEn.query?.pages;
          if (pagesEn) {
            const pageIdEn = Object.keys(pagesEn)[0];
            if (pageIdEn && pagesEn[pageIdEn] && pagesEn[pageIdEn].extract) {
              return pagesEn[pageIdEn].extract;
            }
          }
        }
      }
    }
  } catch (err) {
    console.error("[Wikipedia Extract Error] Falha:", err);
  }
  return null;
}

function generateLocalHint(
  level: number,
  latitude: number,
  longitude: number,
  continent: string,
  drivingSide: string,
  timezone: string,
  tld: string,
  currencyText: string,
  bordersText: string
): string {
  const hemLat = latitude >= 0 ? "Hemisfério Norte" : "Hemisfério Sul";
  const hemLng = longitude >= 0 ? "Hemisfério Oriental" : "Hemisfério Ocidental";

  switch (level) {
    case 1:
      return `🌐 Orientação Espacial: Este local está situado no ${continent}, integrando o ${hemLat} e ${hemLng}. Os veículos trafegam pelo ${drivingSide} e o fuso horário de referência é ${timezone}.`;
    case 2:
      return `🍳 Identidade Local: A moeda oficial é ${currencyText}. O sufixo de internet local é ${tld} e o país ${bordersText.toLowerCase()}. A gastronomia regional apresenta pratos ricos em ingredientes tradicionais do continente.`;
    case 3:
      return `📚 Fato Geral: A região possui forte herança cultural, com uma rica mistura de influências históricas expressas na arquitetura local e nos hábitos cotidianos das pessoas.`;
    case 4:
      return `🎨 Características Culturais: A vegetação predominante, o desenho das construções e os letreiros com caracteres típicos das redondezas contam a história e a identidade vibrante deste ponto geográfico.`;
    default:
      return "Nenhuma pista disponível para este nível.";
  }
}

const FREE_BASE_MODELS = [
  "gemini-3.5-flash",
  "gemini-2.5-flash"
];

// Helper to execute a promise with a timeout
function withTimeout<T>(promise: Promise<T>, ms: number, errorMessage = "Timeout"): Promise<T> {
  let timeoutId: NodeJS.Timeout;
  const timeoutPromise = new Promise<never>((_, reject) => {
    timeoutId = setTimeout(() => {
      reject(new Error(errorMessage));
    }, ms);
  });
  return Promise.race([promise, timeoutPromise]).finally(() => {
    clearTimeout(timeoutId);
  });
}

async function generateGeminiHint(
  level: number,
  latitude: number,
  longitude: number,
  placeName: string,
  description: string,
  continent: string,
  drivingSide: string,
  timezone: string,
  tld: string,
  currencyText: string,
  bordersText: string
): Promise<string> {
  const ai = getGeminiClient();

  // Define four diverse, high-quality, non-categorized perspective guidelines to avoid hallucination
  const hintGuides: Record<number, { focusName: string; focusInstructions: string }> = {
    1: {
      focusName: "Geográfica (espaço físico, relevo, hemisfério e clima)",
      focusInstructions: "Foque em aspectos geográficos físicos e de orientação global (como continente, hemisfério, bioma, vegetação, relevo, fuso horário ou sentido de fluxo do trânsito)."
    },
    2: {
      focusName: "Gastronômica (culinária, pratos e ingredientes tradicionais)",
      focusInstructions: "Foque em pratos típicos, temperos ou culinária associada a esta herança regional, descrevendo sabores ou ingredientes comuns sem revelar o nome do país."
    },
    3: {
      focusName: "Conhecimentos Gerais (marcos, fatos históricos e geopolíticos)",
      focusInstructions: "Foque em fatos de conhecimento geral, eventos de relevância histórica ou trivia sutil sobre o local, como fronteiras, economia, moeda ou sufixo nacional de domínio."
    },
    4: {
      focusName: "Cultural (estilo de vida, idioma e hábitos locais)",
      focusInstructions: "Foque na identidade e costumes locais, folclore, características ou som/alfabeto do idioma falado por lá e traços arquitetônicos residenciais típicos."
    }
  };

  const currentGuide = hintGuides[level] || hintGuides[1];

  const systemInstruction = `Você é o mestre de dicas do Guess The Place. Seu objetivo é ajudar o jogador gerando dicas úteis, intrigantes e realistas baseadas estritamente nos dados de geolocalização e referências reais fornecidas.

DIRETRIZES RÍGIDAS DE SEGURANÇA E NÃO ALUCINAÇÃO:
1. NUNCA revele números de coordenadas geográficas ou sequências de latitude/longitude (como 48.8, 2.29, etc.).
2. NUNCA mencione explicitamente o nome do país, estado, província, cidade ou o nome oficial exato da atração turística. Em vez disso, use sempre termos descritivos elegantes (ex: use "este famoso país sul-americano", "esta metrópole litorânea", "este imponente palácio de ferro").
3. NÃO INVENTE FATOS FALSOS OU HISTÓRIAS DE FANTASIA. Baseie sua resposta apenas em características geográficas, históricas e culturais genuínas.
4. Responda em português brasileiro fluente, correto e natural. Nunca use palavras em inglês (como usar "predominant" em vez de "predominante").
5. Conclua SEMPRE todas as frases por completo. NUNCA deixe o texto cortado ou com ideias inacabadas no final.`;

  // Start with the exact instruction "Escreva em poucas palavras..." as requested by the user
  const prompt = `Escreva em poucas palavras uma dica inteligente de caráter ${currentGuide.focusName} para o local descrito abaixo, sem revelar o nome do local ou país de forma alguma:

Dados do Local Real:
- Atração Turística: "${placeName}"
- Detalhes: "${description}"
- Continente/Região: ${continent}
- Sentido do Trânsito: ${drivingSide}
- Fuso Horário aproximado: ${timezone}
- Moeda Corrente: ${currencyText}
- Domínio de Internet Nacional (TLD): ${tld}
- Fronteira Terrestre: ${bordersText}
- Coordenadas Gerais: Latitude ${latitude >= 0 ? "Norte" : "Sul"}, Longitude ${longitude >= 0 ? "Oriental" : "Ocidental"}

Instruções Adicionais: ${currentGuide.focusInstructions}
Lembre-se: Escreva apenas um parágrafo curto de no máximo 2 a 3 frases objetivas, intrigantes e COMPLETAS. Nunca deixe a última frase cortada.`;

  // Try the free base models list sequentially
  for (const modelId of FREE_BASE_MODELS) {
    try {
      console.log(`[Gemini API] Tentando gerar dica com modelo base gratuito: ${modelId} (Nível: ${level})`);
      // Run with a robust timeout (12s) to prevent hanging while allowing full generation
      const response = await withTimeout(
        ai.models.generateContent({
          model: modelId,
          contents: prompt,
          config: {
            systemInstruction,
            temperature: 0.65,
            maxOutputTokens: 800,
          }
        }),
        12000,
        `Timeout do modelo ${modelId}`
      );

      const text = response.text?.trim();
      if (text) {
        return text;
      }
    } catch (err: any) {
      console.warn(`[Gemini API] Erro ou Timeout com o modelo ${modelId}:`, err.message || err);
      // Continue to the next model in the list
    }
  }

  // If all models failed or timed out, throw an error to invoke the safe local fallback
  throw new Error("Todos os modelos de IA gratuitos falharam ou excederam o tempo limite.");
}

function safetyFilter(text: string, wordsToRedact: string[]): string {
  let filtered = text;
  
  // Match coordinates and long decimal sequences
  filtered = filtered.replace(/\b\d{1,3}[.,]\d{1,6}\b/gi, "[COORDENADAS]");
  filtered = filtered.replace(/\d+([.,]\d+)?\s*[°º]?[^\w\s]*(Norte|Sul|Leste|Oeste|N|S|E|W|L)?/gi, "[COORDENADAS]");

  // Sort words by length descending so we replace longer words first
  const sortedWords = [...wordsToRedact]
    .filter(w => w && w.trim().length > 2)
    .map(w => w.trim())
    .sort((a, b) => b.length - a.length);

  for (const word of sortedWords) {
    const escaped = word.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&');
    const regex = new RegExp(`\\b${escaped}\\w*\\b`, 'gi');
    filtered = filtered.replace(regex, "[REVELADO]");
  }
  
  return filtered;
}

/**
 * Endpoint to extract progressive hints on-demand from live internet databases
 */
app.post("/api/hints/fetch", async (req, res) => {
  const { lat, lng, placeName, description, level } = req.body;

  if (!lat || !lng || !level) {
    return res.status(400).json({ error: "Latitude, longitude e nível são obrigatórios." });
  }

  const latitude = parseFloat(lat);
  const longitude = parseFloat(lng);
  const locDescription = description || "";

  try {
    // 1. Fetch geographic addresses
    const address = await fetchAddressDetails(latitude, longitude);
    
    // Fallback country and state names
    const rawCountry = address?.country || "País Secreto";
    const countryCode = address?.country_code || "";
    const rawState = address?.state || address?.region || "";
    const rawCity = address?.city || address?.town || address?.suburb || "";

    // 2. Fetch socio-economic details from RestCountries if we have countryCode
    let countryDetails: any = null;
    if (countryCode) {
      countryDetails = await fetchCountryDetails(countryCode);
    }

    const continent = countryDetails?.continents?.[0] || countryDetails?.subregion || "Território Global";
    const drivingSide = countryDetails?.car?.side === "left" ? "Lado Esquerdo (Mão Inglesa)" : "Lado Direito";
    const timezone = countryDetails?.timezones?.[0] || "UTC / Variável";

    const tld = countryDetails?.tld?.[0] || "Não listado";
    
    let currencyText = "Não disponível";
    if (countryDetails?.currencies) {
      const keys = Object.keys(countryDetails.currencies);
      if (keys.length > 0) {
        const cur = countryDetails.currencies[keys[0]];
        currencyText = `${cur.name} (${cur.symbol || keys[0]})`;
      }
    }

    let bordersText = "Nenhuma fronteira terrestre";
    if (countryDetails?.borders && countryDetails.borders.length > 0) {
      bordersText = `Faz fronteira terrestre com ${countryDetails.borders.length} outro(s) território(s)`;
    }

    // Build words to redact
    const wordsToRedact: string[] = [rawCountry, rawState, rawCity];
    if (countryCode && countryCode.length > 1) {
      wordsToRedact.push(countryCode);
    }
    if (placeName) {
      const parts = placeName.split(/[\s,.'"-]+/);
      for (const part of parts) {
        if (part.length > 2) {
          wordsToRedact.push(part);
        }
      }
    }

    // Include alternative names/variations of the country
    if (rawCountry.toLowerCase().includes("brasil")) {
      wordsToRedact.push("Brasil", "Brazil", "brasileiro", "brasileira", "brasileiros", "brasileiras");
    } else if (rawCountry.toLowerCase().includes("frança") || rawCountry.toLowerCase().includes("france")) {
      wordsToRedact.push("França", "France", "francesa", "francês", "franceses", "francesas");
    } else if (rawCountry.toLowerCase().includes("estados unidos") || rawCountry.toLowerCase().includes("united states")) {
      wordsToRedact.push("Estados Unidos", "United States", "USA", "americano", "americana", "americanos", "americanas");
    } else if (rawCountry.toLowerCase().includes("japão") || rawCountry.toLowerCase().includes("japan")) {
      wordsToRedact.push("Japão", "Japan", "japonês", "japonesa", "japoneses", "japonesas");
    } else if (rawCountry.toLowerCase().includes("itália") || rawCountry.toLowerCase().includes("italy")) {
      wordsToRedact.push("Itália", "Italy", "italiano", "italiana", "italianos", "italianas");
    } else if (rawCountry.toLowerCase().includes("reino unido") || rawCountry.toLowerCase().includes("united kingdom")) {
      wordsToRedact.push("Reino Unido", "United Kingdom", "UK", "britânico", "britânica", "britânicos", "britânicas");
    } else if (rawCountry.toLowerCase().includes("espanha") || rawCountry.toLowerCase().includes("spain")) {
      wordsToRedact.push("Espanha", "Spain", "espanhol", "espanhola", "espanhóis", "espanholas");
    }

    let hintText = "";
    
    // Try Gemini first
    try {
      hintText = await generateGeminiHint(
        level,
        latitude,
        longitude,
        placeName || "Local Secreto",
        locDescription,
        continent,
        drivingSide,
        timezone,
        tld,
        currencyText,
        bordersText
      );
    } catch (geminiErr) {
      console.warn("[Gemini API Hints Fallback] Usando gerador de dicas local seguro:", geminiErr);
      // Fallback local safe and coordinate-free hints generator
      hintText = generateLocalHint(
        level,
        latitude,
        longitude,
        continent,
        drivingSide,
        timezone,
        tld,
        currencyText,
        bordersText
      );
    }

    // Apply safety filter to censor any accidental leaks of coordinates or name parts
    const filteredHint = safetyFilter(hintText, wordsToRedact);

    return res.json({
      hint: filteredHint,
      country: rawCountry,
    });
  } catch (err: any) {
    console.error("[Fetch Hints Error] Erro:", err);
    return res.status(500).json({ error: "Erro interno ao extrair pistas da internet." });
  }
});

/**
 * Start Express with Vite Integration or Static Serving
 */
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`[Servidor Guess The Place] Rodando na porta ${PORT}`);
  });
}

startServer();
